changeSet.sql:
CREATE TABLE players ( id BIGSERIAL PRIMARY KEY, name VARCHAR(50) NOT NULL UNIQUE, level INTEGER NOT NULL DEFAULT 1, experience BIGINT NOT NULL DEFAULT 0, gold BIGINT NOT NULL DEFAULT 0, current_hp INTEGER NOT NULL,
stat_str INTEGER NOT NULL DEFAULT 8, stat_dex INTEGER NOT NULL DEFAULT 8, stat_con INTEGER NOT NULL DEFAULT 8, stat_int INTEGER NOT NULL DEFAULT 8, stat_wis INTEGER NOT NULL DEFAULT 8, stat_cha INTEGER NOT NULL DEFAULT 8,
created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );
